from flask import Flask, send_from_directory
import os

app = Flask(__name__)

UPLOAD_FOLDER = 'uploads'
ALLOWED_EXTENSIONS = {'txt', 'pdf', 'png', 'jpg', 'jpeg', 'gif'}

def allowed_file(filename):
    return '.' in filename and \
           filename.rsplit('.', 1)[1].lower() in ALLOWED_EXTENSIONS

@app.route('/uploads/<path:filename>')
def upload_file(filename):
    # Canonicalize the file path
    safe_filename = os.path.join(UPLOAD_FOLDER, filename)
    
    # Validate the file path to ensure it stays within the intended base directory
    if not os.path.abspath(safe_filename).startswith(os.path.abspath(UPLOAD_FOLDER)):
        return "Invalid file path", 400
    
    # Send the file from the uploads directory
    return send_from_directory(UPLOAD_FOLDER, filename)

if __name__ == '__main__':
    app.run(debug=True)